import { isNil } from 'lodash-es';
import {
  Children,
  type ReactNode,
  type JSXElementConstructor,
  isValidElement,
} from 'react';

import type { SeriesActionsTemplate } from '@dynatrace/strato-components/charts';

import { DefaultTooltip } from '../components/DefaultTooltip/DefaultTooltip.js';
import type { Location } from '../types/location.js';
import type {
  ChoroplethLayerTooltipData,
  LayerTooltipData,
  LayerTooltipHandler,
} from '../types/tooltip.js';

export const defaultTooltipHandler: LayerTooltipHandler = (
  closestPoint: LayerTooltipData,
  layerData?: LayerTooltipData[],
) => <DefaultTooltip closestPoint={closestPoint} layerData={layerData} />;

(defaultTooltipHandler as { __isDefault?: boolean }).__isDefault = true;

const createDefaultHandlerWithActions = (
  seriesActions: (
    data: Location | ChoroplethLayerTooltipData,
  ) => SeriesActionsTemplate,
): LayerTooltipHandler => {
  const handler: LayerTooltipHandler = (
    closestPoint: LayerTooltipData,
    layerData?: LayerTooltipData[],
  ) => (
    <DefaultTooltip
      closestPoint={closestPoint}
      layerData={layerData}
      seriesActions={seriesActions}
    />
  );
  (handler as { __isDefault?: boolean }).__isDefault = true;
  return handler;
};

export const isDefaultTooltipHandler = (
  handler: LayerTooltipHandler,
): boolean => (handler as { __isDefault?: boolean }).__isDefault ?? false;

/**
 * It returns the tooltip template handler or undefined (tooltip disabled).
 *
 * - No tooltip slot found (undefined) → default tooltip handler.
 * - Tooltip slot with `null` children → `null` (tooltip disabled).
 * - Tooltip slot with `undefined` children → default tooltip handler.
 * - Tooltip slot with a custom handler → that handler.
 * @param children -
 * @param layerType -
 */
export interface TooltipTemplateResult {
  handler: LayerTooltipHandler | undefined;
  hidden?: boolean;
  symbolAlignment?: 'left' | 'right';
}

export function useTooltipTemplate<T>(
  children: ReactNode | undefined,
  layerType: string | JSXElementConstructor<T>,
): LayerTooltipHandler | undefined;
export function useTooltipTemplate<T>(
  children: ReactNode | undefined,
  layerType: string | JSXElementConstructor<T>,
  options: { extractProps: true },
): TooltipTemplateResult;
export function useTooltipTemplate<T>(
  children: ReactNode | undefined,
  layerType: string | JSXElementConstructor<T>,
  options?: { extractProps: true },
): LayerTooltipHandler | undefined | TooltipTemplateResult {
  let template: LayerTooltipHandler | undefined = undefined;
  let hidden: boolean | undefined = undefined;
  let symbolAlignment: 'left' | 'right' | undefined = undefined;

  Children.forEach(children, (child) => {
    if (
      isValidElement<{
        children: LayerTooltipHandler;
        seriesActions?: (
          data: Location | ChoroplethLayerTooltipData,
        ) => SeriesActionsTemplate;
        hidden?: boolean;
        symbolAlignment?: 'left' | 'right';
      }>(child) &&
      child.type === layerType
    ) {
      hidden = child.props.hidden;
      symbolAlignment = child.props.symbolAlignment;

      if (child.props.hidden) {
        template = undefined;
        return;
      }
      if (isNil(child.props.children)) {
        template = child.props.seriesActions
          ? createDefaultHandlerWithActions(child.props.seriesActions)
          : defaultTooltipHandler;
      } else {
        template = child.props.children;
      }
    }
  });

  if (options?.extractProps) {
    return {
      handler: hidden ? undefined : template ?? defaultTooltipHandler,
      hidden,
      symbolAlignment,
    };
  }

  return hidden ? undefined : template ?? defaultTooltipHandler;
}
